local TD = TD.td1madao["ydj_dst_td1madao"] local myComponent = Class(function(self, inst)     self.inst = inst end) function myComponent:player_castCondition(tag)     local player = self.inst     local skill = TD.csv(self.inst):get("skillcast")     local cd = skill[tag].cd     if TD.G.IS_PAUSE then         return false     end     if cd > 0 then         return false     end     if player:HasTag("playerghost") then         return false     end     if player.prefab ~= TD.CHAR then         return false     end     return true end function myComponent:server_castCondition(tag)     local player = self.inst     local skill = TD.csv(self.inst):get("skillcast")     if not skill[tag] then         skill[tag] = {}         skill[tag].cd = 0     end     local cd = skill[tag].cd     if cd > 0 then         return false     end     if player:HasTag("playerghost") or TD.die(player) then         return false     end     if player.prefab ~= TD.CHAR then         return false     end     if not player.sg:HasStateTag("attack") and             (player.sg:HasStateTag("busy") or                     player.sg:HasStateTag("pausepredict") or                     player.sg:HasStateTag("td1madao_skill") or                     player.sg:HasStateTag("tent")) then         return false     end     return true end return myComponent 